// --- Title ---
const rawTitle = document.title || '';
const title = rawTitle.replace(/\s*[-–]\s*Gemini\s*$/i, '').trim() || 'untitled';

// --- Messages ---
const userEls = document.querySelectorAll(
  '.query-text, .user-query-text, [data-message-author-role="user"] .whitespace-pre-wrap'
);
const modelEls = document.querySelectorAll(
  'model-response .markdown, .model-response-text, [data-message-author-role="model"] .markdown'
);

const userTexts  = Array.from(userEls).map(el => el.innerText.trim()).filter(Boolean);
const modelTexts = Array.from(modelEls).map(el => el.innerText.trim()).filter(Boolean);

const lines = [];
const len = Math.max(userTexts.length, modelTexts.length);
for (let i = 0; i < len; i++) {
  if (userTexts[i])  lines.push('**User:**\n\n' + userTexts[i]);
  if (modelTexts[i]) lines.push('**Gemini:**\n\n' + modelTexts[i]);
}

const content = lines.length > 0
  ? lines.join('\n\n---\n\n')
  : document.body.innerText.slice(0, 8000);

automaSetVariable('title',   title);
automaSetVariable('content', content);
automaNextBlock({ data: '' });

const title   = automaRefData('variables', 'title');
const content = automaRefData('variables', 'content');

const today    = new Date().toISOString().slice(0, 10);
const markdown = `# ${title}\n\n> Downloaded: ${today}  \n> Source: ${location.href}\n\n---\n\n${content}\n`;

const filename = (title
  .replace(/[^a-z0-9]/gi, '_')
  .replace(/_+/g, '_')
  .replace(/^_|_$/g, '')
  .toLowerCase() || 'gemini') + '.md';

const blob = new Blob([markdown], { type: 'text/markdown' });
const url  = URL.createObjectURL(blob);
const a    = document.createElement('a');
a.href     = url;
a.download = filename;
document.body.appendChild(a);
a.click();
setTimeout(() => { URL.revokeObjectURL(url); a.remove(); }, 1000);

automaNextBlock({ data: `Saved as ${filename}` });
